#!/usr/bin/env bash
# Gold solution for swc PR #11692 -- adds Flow `declare export default
# interface ...` strip-path support to swc_ecma_parser.
#
# Idempotent: re-running the script after a successful apply is a no-op.

set -euo pipefail

cd /workspace/swc

TARGET="crates/swc_ecma_parser/src/parser/typescript.rs"

# Idempotency check -- distinctive line from the inlined patch.
if grep -q 'p.input().is(Token::Interface)' "$TARGET"; then
    echo "Patch already applied -- nothing to do."
    exit 0
fi

PATCH_FILE=$(mktemp)
trap 'rm -f "$PATCH_FILE"' EXIT

base64 -d > "$PATCH_FILE" <<'B64'

B64

git apply --whitespace=nowarn "$PATCH_FILE"
echo "Applied PR #11692 gold patch."
